import{_ as e,c as n,a2 as t,o as i}from"./chunks/framework.6x3wfQve.js";const p=JSON.parse('{"title":"Pengenalan Clean Architecture","description":"","frontmatter":{"next":false},"headers":[],"relativePath":"src/5_clean_architecture/a_pengertian/index.md","filePath":"src/5_clean_architecture/a_pengertian/index.md"}'),r={name:"src/5_clean_architecture/a_pengertian/index.md"};function s(o,a,l,u,m,d){return i(),n("div",null,a[0]||(a[0]=[t(`<h1 id="pengenalan-clean-architecture" tabindex="-1">Pengenalan Clean Architecture <a class="header-anchor" href="#pengenalan-clean-architecture" aria-label="Permalink to &quot;Pengenalan Clean Architecture&quot;">​</a></h1><h2 id="mengapa-aplikasi-butuh-arsitektur" tabindex="-1">Mengapa Aplikasi Butuh Arsitektur? <a class="header-anchor" href="#mengapa-aplikasi-butuh-arsitektur" aria-label="Permalink to &quot;Mengapa Aplikasi Butuh Arsitektur?&quot;">​</a></h2><p>Sejauh ini, saat belajar dasar Flutter, kita menaruh semua logika kita ke dalam satu file <code>main.dart</code> atau dilekatkan langsung di UI Button <code>onPressed</code>. Logika API (mengambil JSON dari internet), Validasi Password (Logika Bisnis), dan tampilan layar Text Input (UI) bercampur aduk menjadi satu tumpukan mengerikan <em>(Spaghetti Code)</em>.</p><p>Aplikasi kecil masih bisa bertahan dengan cara itu, namun Raion Internship membekali kamu untuk siap dengan Standar Enterprise skala besar. Jika kamu membuat aplikasi Toko Online (ShopEase) yang melibatkan ratusan fitur, tidak akan ada orang yang bisa membaca, menambah, atau memperbaiki aplikasimu.</p><p><strong>Clean Architecture (Arsitektur Bersih)</strong> adalah sebuah pedoman rancang bangun aplikasi yang ditemukan oleh Uncle Bob (Robert C. Martin). Tujuan utamanya adalah: <strong>Memisahkan Peran/Kode agar tidak saling mengetahui (Decoupling) sehingga mudah diuji (Testable) dan diperluas skalanya (Scalable)</strong>.</p><h2 id="pemisahan-tiga-layer-utama" tabindex="-1">Pemisahan Tiga Layer Utama <a class="header-anchor" href="#pemisahan-tiga-layer-utama" aria-label="Permalink to &quot;Pemisahan Tiga Layer Utama&quot;">​</a></h2><p>Meskipun Flutter tidak memaksa pola apapun, komunitas global Flutter secara de-facto mengadopsi modifikasi <em>Clean Architecture</em> menjadi Tiga Lapisan (Layer) folder utama: <strong>Domain</strong>, <strong>Data</strong>, dan <strong>Presentation</strong>.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lib/</span></span>
<span class="line"><span>├── core/                   (Bagian Umum/Reusable, spt konfigurasi, style text, error types)</span></span>
<span class="line"><span>└── features/               (Modul Berbasis Fitur, misalnya Folder Checkout dan Folder Auth)</span></span>
<span class="line"><span>    └── shop_ease_cart/     (Contoh Nama Fitur)</span></span>
<span class="line"><span>        ├── domain/         (Jantung &amp; Aturan Aplikasi)</span></span>
<span class="line"><span>        ├── data/           (Kuli Data Internet &amp; Cache Lokal)</span></span>
<span class="line"><span>        └── presentation/   (Tampilan Layar &amp; Tombol)</span></span></code></pre></div><p>Mari bedah tanggung jawab masing-masing lapisan folder tersebut!</p><hr><h3 id="layer-1-domain" tabindex="-1">Layer 1: Domain <a class="header-anchor" href="#layer-1-domain" aria-label="Permalink to &quot;Layer 1: Domain&quot;">​</a></h3><p>Ini adalah jantung terdalam dari aplikasi kamu. Layer ini berisi <strong>Bisnis Logika / Aturan Pokok</strong> dan struktur utama. Ia <strong>SAMA SEKALI TIDAK BOLEH TAHU</strong> apakah aplikasi ini dibuat pakai Flutter, Website, atau konek ke Firebase/MySQL.</p><p>Domain harus merdeka (Independent), hanya berisi kode murni bahasa Dart.</p><ul><li><strong>Entities:</strong> Kelas inti model nyata. Contoh: Class <code>ShoppingCart</code> yang terdiri dari list <code>ProductItem</code> dan total Harga.</li><li><strong>Use Cases (Interactors):</strong> Kelas aksi spesifik yang disuruh pengguna. Contoh: <code>UpdateCartItemQuantity</code>, <code>CalculateTotalPrice</code>.</li><li><strong>Repositories (Interfaces/Abstraksi):</strong> Kontrak kesepakatan. Domain cuma membuat &quot;Papan Pengumuman Aturan&quot; misal (<em>abstract class</em>) <code>ShopRepository</code> dengan fungsi kosongan <code>List&lt;Product&gt; getProducts();</code>. Siapapun yang repot mengambil datanya dari internet atau memori, bukan urusan Domain.</li></ul><h3 id="layer-2-data" tabindex="-1">Layer 2: Data <a class="header-anchor" href="#layer-2-data" aria-label="Permalink to &quot;Layer 2: Data&quot;">​</a></h3><p>Berposisi di luar menjaga Domain. Ini adalah Kuli Pekerja aslinya yang melakukan &quot;Kotornya pekerjaan I/O Internet&quot;. Data layer akan mengeksekusi janji yang ditulis oleh Interfaces di Domain.</p><ul><li><strong>Repositories (Implementation):</strong> Kelas turunan konkrit yang mengimplementasikan Papan Pengumuman. Bertugas menyambung kepingan Puzzle dari DataSource dan meneruskannya ke Domain.</li><li><strong>Data Models:</strong> Representasi <code>Entity</code> Domain, tetapi disesuaikan dengan struktur <em>database</em>. Di sini kita menulis fungsi Serialisasi JSON (<code>fromJson</code> &amp; <code>toJson</code>).</li><li><strong>Data Sources:</strong> Tempat nyata yang mencangkul data lewat Remote (Menembak internet API ke Backend) dan Local (Menyimpan riwayat Offline di HP menggunakan SQLite/Room/SharedPreference).</li></ul><h3 id="layer-3-presentation-lapisan-tampilan-ui" tabindex="-1">Layer 3: Presentation (Lapisan Tampilan / UI) <a class="header-anchor" href="#layer-3-presentation-lapisan-tampilan-ui" aria-label="Permalink to &quot;Layer 3: Presentation (Lapisan Tampilan / UI)&quot;">​</a></h3><p>Layer ini tempatnya Widget pohon Flutter bernaung! Ini berhubungan langsung dengan tombol yang di tekan pengguna.</p><ul><li><strong>Pages / Screens:</strong> Layout utama layar HP-mu (<code>Scaffold</code>, <code>AppBar</code>, dll).</li><li><strong>Widgets:</strong> Potongan kerikil UI kecil (misal: Komponen terpisah berupa Card Produk merah).</li><li><strong>Status Controllers (State Management):</strong> Otak dari <em>Screen</em> (Biasanya memakai <code>BLoC</code>, <code>Provider</code>, atau <code>GetxController</code>). Pengontrol ini yang memerintahkan (memanggil Use Case Domain) jika sebuah tombol diklik pengguna, lalu mengirimkan status &quot;Memuat (Loading..)&quot;, &quot;Sukses Mengambil (Loaded)&quot; memanggil Data Layer.</li></ul><hr><h3 id="alur-singkat-kejadian-flow-of-control" tabindex="-1">Alur Singkat Kejadian (<em>Flow of Control</em>) <a class="header-anchor" href="#alur-singkat-kejadian-flow-of-control" aria-label="Permalink to &quot;Alur Singkat Kejadian (*Flow of Control*)&quot;">​</a></h3><p>Biar mudah dipahami, ini analogi dari <em>&quot;Flow Clean Architecture&quot;</em> di saat aplikasi Toko kita pertama kali dibuka:</p><ol><li><strong>Presentation (UI)</strong> Halaman Muka terbuka, statusnya &quot;Loading Muter-Muter..&quot;. Ia lalu berteriak ke Pengontrol State <em>(BLoC/Provider)</em>: <em>&quot;Hei, ambilkan saya seluruh List Produk!&quot;</em>.</li><li><strong>Pengontrol State</strong> mendengar dan berkata pada <strong>Domain (Use Case)</strong>: <em>&quot;Eksekusi perintah AmbilDaftarProduk().&quot;</em></li><li><strong>Domain (Use Case)</strong> berkata kepada Pelayannya <strong>(Interfaces Domain)</strong>: Yang disaut dan <em>dijalankan sesungguhnya oleh</em> <strong>Data (Repository Implementation)</strong> <em>&quot;Tolong kerjakan perintah saya.&quot;</em>.</li><li><strong>Data (Repository)</strong> menyuruh <strong>Remote Data Source</strong>, &quot;Tembak API Internet Backend di <code>https://shopease.raion...</code> sekarang!&quot;.</li><li>Setelah data Remote balik menjadi Model JSON, <strong>Data (Repository)</strong> membersihkannya menjadi sebuah Domain <code>Entity</code> Murni nan Rapi dan memberikannya ke <strong>Domain (Use Case)</strong>.</li><li><strong>Pengontrol State</strong> mendapatkan <em>Entity</em> Produk Murni List tersebut dari Use Case, dan memberitahu UI, <em>&quot;Ini datanya ada Total 20 Baju! Status BERHASIL!&quot;</em>.</li><li><strong>Presentation (UI)</strong> Langsung berhenti Loading Muter-Muter, me-<em>Rebuild</em> layarnya dari statis menjadi List Kardus Barang yang bisa diklik berdasarkan List Item baju yang diberikan!</li></ol><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Pada awalnya membuat Clean Architecture itu menyiksa <em>(Over-engineering)</em> karena kode yang sedikit tapi dipaksa membuat file yang banyak dan folder yang dalam. Namun, begitu kamu ditugaskan mengerjakan modul raksasa <strong>Skala Industri bersama puluhan Programmer lain secara serentak</strong>, struktur pemecahan inilah yang akan menolongmu menjaga Kode dari kehancuran absolut (Bugs).</p></div>`,25)]))}const k=e(r,[["render",s]]);export{p as __pageData,k as default};
